36	
37	export interface FactoryListRow {
38	  id: number;
39	  factory_name: string | null;
40	  factory_nickname: string | null;
41	  sort_order: number | null;
42	}
43	
44	export interface FactorySampleOfferRow {
45	  sample_id_pk: number;
46	  sample_name?: string | null;
