507	  dateComparator(date1, date2) {
508	    function formatedDate(input) {
509	      if (input) {
510	        if (input.includes("-")) {
511	          var datePart = input.match(/\d+/g),
512	            year = datePart[0].substring(), // get only two digits
513	            month = datePart[1], day = datePart[2];
514	          return month + '/' + day + '/' + year;
515	        } else {
516	          return input
517	        }
518	      }
519	    }
520	
521	    function monthToComparableNumber(date) {
522	
523	      if (date === undefined || date === null || date.length !== 10) {
524	        return date.length;
525	      }
526	      var yearNumber = date.substring(6, 10);
527	      var dayNumber = date.substring(3, 5);
528	      var monthNumber = date.substring(0, 2);
529	      var result = yearNumber * 10000 + monthNumber * 100 + dayNumber;
530	      return result;
531	    }
532	
533	    date1 = formatedDate(date1)
534	    date2 = formatedDate(date2)
535	    var date1Number = monthToComparableNumber(date1);
536	    var date2Number = monthToComparableNumber(date2);
537	    if (date1Number === null && date2Number === null) {
538	      return 0;
539	    }
540	    if (date1Number === null) {
541	      return -1;
542	    }
543	    if (date2Number === null) {
544	      return 1;
545	    }
546	    return date1Number - date2Number;
547	  }
